"use client";

import { useMemo, useState } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { DATASETS, getDataset } from "@/lib/datasets";
import {
  MODE_INFO,
  VIEW_MODES,
  buildHeatmapCells,
  starsLabel,
} from "@/lib/heatmap-utils";
import type { ViewMode } from "@/lib/types";
import { Heatmap } from "./Heatmap";
import { Slider } from "./Slider";

export function ClusteringDashboard() {
  const [datasetId, setDatasetId] = useState("movies");
  const [mode, setMode] = useState<ViewMode>("original");
  const [contrast, setContrast] = useState(1.3);
  const [noise, setNoise] = useState(0.03);

  const dataset = getDataset(datasetId);
  const info = MODE_INFO[mode];

  const cells = useMemo(
    () => buildHeatmapCells(dataset, mode, noise),
    [dataset, mode, noise],
  );

  const miniViews = VIEW_MODES.map((m) => ({
    mode: m,
    cells: buildHeatmapCells(dataset, m, noise),
    info: MODE_INFO[m],
  }));

  const coreDatasets = DATASETS.filter((d) => d.tier === "core");
  const advancedDatasets = DATASETS.filter((d) => d.tier === "advanced");

  return (
    <div className="min-h-screen bg-[#FFFDF7] text-black">
      {/* Sharp decorative stripes */}
      <div
        className="pointer-events-none fixed right-0 top-0 h-full w-3"
        style={{
          background: `repeating-linear-gradient(
            -45deg,
            ${dataset.theme.accent},
            ${dataset.theme.accent} 6px,
            transparent 6px,
            transparent 12px
          )`,
        }}
      />

      <div className="relative mx-auto max-w-7xl px-5 py-8 md:px-8 md:py-10">
        {/* Header */}
        <header className="mb-8 border-b-4 border-black pb-6">
          <div className="flex flex-wrap items-end justify-between gap-4">
            <div>
              <p className="font-mono text-[10px] font-bold uppercase tracking-[0.25em] text-black/50">
                Visual Analytics · Clustering Lab
              </p>
              <motion.h1
                key={dataset.id}
                initial={{ opacity: 0, x: -12 }}
                animate={{ opacity: 1, x: 0 }}
                className="mt-2 text-4xl font-black uppercase tracking-tight md:text-5xl"
                style={{ color: dataset.theme.accent }}
              >
                Cluster
              </motion.h1>
              <p className="mt-2 max-w-xl text-sm font-medium leading-relaxed text-black/70">
                One dashboard. Three real-world matrices. Toggle clustering modes and
                watch patterns emerge — or stay hidden.
              </p>
            </div>
            <div
              className="border-3 border-black px-4 py-2 font-mono text-xs font-bold uppercase"
              style={{ backgroundColor: dataset.theme.secondary, boxShadow: "4px 4px 0 #0A0A0A" }}
            >
              {dataset.title}
            </div>
          </div>
        </header>

        <div className="grid gap-6 lg:grid-cols-[260px_1fr]">
          {/* Left nav */}
          <aside className="space-y-4">
            {/* Dataset picker */}
            <div className="border-3 border-black bg-white" style={{ boxShadow: "6px 6px 0 #0A0A0A" }}>
              <div
                className="border-b-3 border-black px-4 py-2 font-mono text-[10px] font-bold uppercase tracking-widest"
                style={{ backgroundColor: dataset.theme.accentLight }}
              >
                Datasets
              </div>
              <div className="p-2">
                <p className="px-2 py-1 font-mono text-[9px] font-bold uppercase tracking-widest text-black/40">
                  Core
                </p>
                {coreDatasets.map((d) => (
                  <DatasetButton
                    key={d.id}
                    dataset={d}
                    active={datasetId === d.id}
                    onClick={() => {
                      setDatasetId(d.id);
                      setMode("original");
                    }}
                  />
                ))}
                <p className="mt-2 px-2 py-1 font-mono text-[9px] font-bold uppercase tracking-widest text-black/40">
                  Advanced
                </p>
                {advancedDatasets.map((d) => (
                  <DatasetButton
                    key={d.id}
                    dataset={d}
                    active={datasetId === d.id}
                    onClick={() => {
                      setDatasetId(d.id);
                      setMode("original");
                    }}
                  />
                ))}
              </div>
            </div>

            {/* Mode picker */}
            <div className="border-3 border-black bg-white" style={{ boxShadow: "6px 6px 0 #0A0A0A" }}>
              <div className="border-b-3 border-black bg-black px-4 py-2 font-mono text-[10px] font-bold uppercase tracking-widest text-white">
                Clustering mode
              </div>
              <div className="p-2 space-y-1">
                {VIEW_MODES.map((m) => {
                  const active = mode === m;
                  const meta = MODE_INFO[m];
                  return (
                    <button
                      key={m}
                      onClick={() => setMode(m)}
                      className="relative w-full px-3 py-2.5 text-left transition-colors"
                      style={{
                        backgroundColor: active ? dataset.theme.accent : "transparent",
                        color: active ? "#FFFDF7" : "#0A0A0A",
                      }}
                    >
                      <span className="text-xs font-bold uppercase tracking-wide">
                        {meta.title}
                      </span>
                      <span
                        className="mt-0.5 block font-mono text-[9px] uppercase"
                        style={{ opacity: active ? 0.85 : 0.45 }}
                      >
                        {meta.tag}
                      </span>
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Sliders */}
            <div className="border-3 border-black bg-white p-4" style={{ boxShadow: "6px 6px 0 #0A0A0A" }}>
              <p className="mb-4 font-mono text-[10px] font-bold uppercase tracking-widest text-black/50">
                Controls
              </p>
              <div className="space-y-5">
                <Slider
                  label="Contrast"
                  value={contrast}
                  min={0.7}
                  max={2.5}
                  step={0.1}
                  accent={dataset.theme.accent}
                  onChange={setContrast}
                  format={(v) => `${v.toFixed(1)}×`}
                />
                <Slider
                  label="Noise"
                  value={noise}
                  min={0}
                  max={0.18}
                  step={0.01}
                  accent={dataset.theme.secondary}
                  onChange={setNoise}
                  format={(v) => `${(v * 100).toFixed(0)}%`}
                />
              </div>
            </div>
          </aside>

          {/* Main panel */}
          <main className="space-y-5">
            <AnimatePresence mode="wait">
              <motion.div
                key={`${datasetId}-${mode}`}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -6 }}
                transition={{ duration: 0.2 }}
                className="border-3 border-black bg-white"
                style={{ boxShadow: `8px 8px 0 ${dataset.theme.accent}` }}
              >
                {/* Panel header */}
                <div
                  className="flex flex-wrap items-center justify-between gap-3 border-b-3 border-black px-5 py-4"
                  style={{ backgroundColor: dataset.theme.accentLight }}
                >
                  <div>
                    <h2 className="text-lg font-black uppercase tracking-tight">
                      {dataset.title}
                    </h2>
                    <p className="mt-0.5 text-xs font-medium text-black/60">
                      {dataset.subtitle}
                    </p>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="font-mono text-sm" style={{ color: dataset.theme.accent }}>
                      {starsLabel(dataset.stars)}
                    </span>
                    <span
                      className="border-2 border-black px-2 py-0.5 font-mono text-[9px] font-bold uppercase"
                      style={{ backgroundColor: dataset.theme.secondary }}
                    >
                      {info.tag}
                    </span>
                  </div>
                </div>

                {/* Insight bar */}
                <div className="border-b-3 border-black px-5 py-3">
                  <p className="text-sm font-semibold">{info.title}</p>
                  <p className="mt-1 text-xs text-black/60">{info.subtitle}</p>
                  {mode === "row" && (
                    <p className="mt-2 text-xs font-medium" style={{ color: dataset.theme.accent }}>
                      → {dataset.clusteringInsight}
                    </p>
                  )}
                  {mode === "column" && (
                    <p className="mt-2 text-xs font-medium" style={{ color: dataset.theme.accent }}>
                      → {dataset.colClusterLabel}
                    </p>
                  )}
                  {mode === "bicluster" && (
                    <p className="mt-2 text-xs font-medium" style={{ color: dataset.theme.accent }}>
                      → {dataset.biclusterInsight}
                    </p>
                  )}
                </div>

                {/* Heatmap */}
                <div className="flex justify-center overflow-x-auto px-5 py-8">
                  <Heatmap
                    dataset={dataset}
                    cells={cells}
                    mode={mode}
                    contrast={contrast}
                    highlightBlock={dataset.biclusterBlock}
                  />
                </div>

                {/* Legend */}
                <div className="flex flex-wrap items-center justify-between gap-3 border-t-3 border-black px-5 py-3">
                  <div className="flex items-center gap-3 font-mono text-[9px] font-bold uppercase">
                    <span className="flex items-center gap-1.5">
                      <span className="h-4 w-4 border border-black/20" style={{ background: dataset.theme.heatLow }} />
                      Low
                    </span>
                    <span className="flex items-center gap-1.5">
                      <span className="h-4 w-4 border border-black/20" style={{ background: dataset.theme.heatMid }} />
                      Mid
                    </span>
                    <span className="flex items-center gap-1.5">
                      <span className="h-4 w-4 border border-black/20" style={{ background: dataset.theme.heatHigh }} />
                      High
                    </span>
                  </div>
                  <p className="font-mono text-[9px] text-black/40">
                    {dataset.rows.length} {dataset.rowLabel} × {dataset.cols.length} {dataset.colLabel}
                  </p>
                </div>
              </motion.div>
            </AnimatePresence>

            {/* Mini comparison */}
            <section>
              <h3 className="mb-3 font-mono text-[10px] font-bold uppercase tracking-[0.2em] text-black/50">
                All modes — click to switch
              </h3>
              <div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-4">
                {miniViews.map(({ mode: m, cells: c, info: i }) => (
                  <motion.button
                    key={m}
                    onClick={() => setMode(m)}
                    whileHover={{ y: -3 }}
                    whileTap={{ scale: 0.98 }}
                    className="border-3 border-black bg-white p-3 text-left"
                    style={{
                      boxShadow: mode === m ? `5px 5px 0 ${dataset.theme.accent}` : "3px 3px 0 #0A0A0A",
                      outline: mode === m ? `3px solid ${dataset.theme.accent}` : "none",
                      outlineOffset: -3,
                    }}
                  >
                    <p className="font-mono text-[9px] font-bold uppercase tracking-widest text-black/50">
                      {i.tag}
                    </p>
                    <p className="mt-1 text-xs font-bold uppercase">{i.title}</p>
                    <div className="mt-3 flex justify-center">
                      <Heatmap
                        dataset={dataset}
                        cells={c}
                        mode={m}
                        contrast={contrast}
                        cellSize={14}
                        showLabels={false}
                        compact
                      />
                    </div>
                  </motion.button>
                ))}
              </div>
            </section>

            {/* Concept cards */}
            <div className="grid gap-4 md:grid-cols-2">
              <ConceptCard
                title="Regular clustering"
                accent={dataset.theme.accent}
                active={mode === "row" || mode === "column"}
                body={`Groups data in ONE direction. ${dataset.rowClusterLabel} appear when clustering rows. ${dataset.colClusterLabel} appear when clustering columns. Never both at once.`}
              />
              <ConceptCard
                title="Biclustering"
                accent={dataset.theme.secondary}
                active={mode === "bicluster"}
                body={dataset.biclusterInsight}
                highlight={dataset.biclusterBlock.label}
              />
            </div>
          </main>
        </div>
      </div>
    </div>
  );
}

function DatasetButton({
  dataset,
  active,
  onClick,
}: {
  dataset: (typeof DATASETS)[0];
  active: boolean;
  onClick: () => void;
}) {
  return (
    <button
      onClick={onClick}
      className="flex w-full items-center justify-between px-3 py-2.5 text-left transition-all"
      style={{
        backgroundColor: active ? dataset.theme.accent : "transparent",
        color: active ? "#FFFDF7" : "#0A0A0A",
      }}
    >
      <span className="text-xs font-bold">{dataset.title}</span>
      <span className="font-mono text-[9px]" style={{ opacity: active ? 0.9 : 0.5 }}>
        {starsLabel(dataset.stars)}
      </span>
    </button>
  );
}

function ConceptCard({
  title,
  body,
  accent,
  active,
  highlight,
}: {
  title: string;
  body: string;
  accent: string;
  active: boolean;
  highlight?: string;
}) {
  return (
    <motion.div
      animate={{
        boxShadow: active ? `6px 6px 0 ${accent}` : "4px 4px 0 #0A0A0A",
      }}
      className="border-3 border-black bg-white p-5"
    >
      <h3
        className="text-sm font-black uppercase tracking-wide"
        style={{ color: accent }}
      >
        {title}
      </h3>
      <p className="mt-2 text-xs leading-relaxed text-black/70">{body}</p>
      {highlight && active && (
        <p
          className="mt-3 inline-block border-2 border-black px-2 py-1 font-mono text-[9px] font-bold uppercase"
          style={{ backgroundColor: accent, color: "#0A0A0A" }}
        >
          {highlight}
        </p>
      )}
    </motion.div>
  );
}
